INSERT INTO `blogs` VALUES (_binary '',1,'2025-07-01 10:00:00.000000',1,NULL,NULL,'Summer Fashion Trends 2025','<h2>✨ Bí kíp chọn áo local brand cực chất cho Gen Z</h2><p>Không còn là xu hướng nữa, local brand đã trở thành tiếng nói riêng của giới trẻ – mạnh mẽ, cá tính và đầy cảm hứng.</p><img src=\"https://example.com/images/localbrand-style.jpg\" alt=\"Phong cách local brand\" style=\"max-width: 100%; border-radius: 8px; margin: 16px 0;\" /><p>Để chọn được chiếc áo \"chuẩn bài\", bạn nên lưu ý vài điều sau:</p><ul><li><strong>Chất liệu</strong> thoáng mát, dễ chịu – ưu tiên cotton hoặc chất vải recycle</li><li><strong>Phối màu</strong> độc lạ nhưng không \"gắt\" – hợp gu mà vẫn nổi bật</li><li><strong>Logo/Design</strong> phải có câu chuyện – thể hiện vibe riêng của bạn</li></ul><blockquote style=\"font-style: italic; border-left: 4px solid #ccc; padding-left: 12px; color: #555;\">\"Đừng mặc để trông đẹp, hãy mặc để kể một câu chuyện.\"</blockquote><p>Local brand không chỉ là thời trang – đó là tuyên ngôn phong cách của chính bạn. <strong>Chọn đúng áo, bật đúng vibe</strong> – thế là toả sáng!</p>'),(_binary '',2,'2025-07-01 10:00:00.000000',1,NULL,NULL,'How to Style Sneakers','<h2>✨ Bí kíp chọn áo local brand cực chất cho Gen Z</h2><p>Không còn là xu hướng nữa, local brand đã trở thành tiếng nói riêng của giới trẻ – mạnh mẽ, cá tính và đầy cảm hứng.</p><img src=\"https://example.com/images/localbrand-style.jpg\" alt=\"Phong cách local brand\" style=\"max-width: 100%; border-radius: 8px; margin: 16px 0;\" /><p>Để chọn được chiếc áo \"chuẩn bài\", bạn nên lưu ý vài điều sau:</p><ul><li><strong>Chất liệu</strong> thoáng mát, dễ chịu – ưu tiên cotton hoặc chất vải recycle</li><li><strong>Phối màu</strong> độc lạ nhưng không \"gắt\" – hợp gu mà vẫn nổi bật</li><li><strong>Logo/Design</strong> phải có câu chuyện – thể hiện vibe riêng của bạn</li></ul><blockquote style=\"font-style: italic; border-left: 4px solid #ccc; padding-left: 12px; color: #555;\">\"Đừng mặc để